  ('dietitian-moex-11454', 'dietitian', 'dietitian-moex-092-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列那一單位之工作內容為製訂食物平衡表及家政推廣工作？ 農會  糧食局  行政院衛生署  行政院農業委員會', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "e959493419d7", "answer_pdf_sha1": "ec7f59b9c927", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11455', 'dietitian', 'dietitian-moex-092-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '從事營養教育的過程，第一步驟是要： 採用適當的方法  設定教學的目標  了解對象和問題  營養知識的評價', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "e959493419d7", "answer_pdf_sha1": "ec7f59b9c927", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11456', 'dietitian', 'dietitian-moex-092-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '採用演講進行衛教，其最大缺點是： 不易找到容易吸引聽眾的演講者  受限時間，知識傳達有限 不易營造熱烈氣氛    容易造成單向溝通', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "e959493419d7", "answer_pdf_sha1": "ec7f59b9c927", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11457', 'dietitian', 'dietitian-moex-092-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '戴爾（Dale）將人們學習的經驗比喻成一個多層次的錐形體，越往錐形體的底層，越代表下列何種經驗？ 具體有目的的學習  觀察中學習  圖像學習  抽象學習', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "e959493419d7", "answer_pdf_sha1": "ec7f59b9c927", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11458', 'dietitian', 'dietitian-moex-092-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', 'Russell等專家所提出的ASSURE教學模式中，R所代表的是： Representative  Require learner response  Restate objectives  Report', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "e959493419d7", "answer_pdf_sha1": "ec7f59b9c927", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11459', 'dietitian', 'dietitian-moex-092-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列關於飲酒之敘述何者正確？ 會幫助各種營養素的吸收，尤其是脂溶性維生素  有能量，1毫升相當於5大卡熱量 懷孕期間飲酒容易產生畸形兒  增加思考判斷力', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "e959493419d7", "answer_pdf_sha1": "ec7f59b9c927", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11460', 'dietitian', 'dietitian-moex-092-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '尿中肌酸酐（Creatinine）排出量可以用來評估： 肝功能    體蛋白(Somatic protein)含量 內臟蛋白(Visceral protein)含量  體脂肪含量', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "e959493419d7", "answer_pdf_sha1": "ec7f59b9c927", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11461', 'dietitian', 'dietitian-moex-092-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '王先生無營養師執照，受雇於五星級觀光飯店擔任行政總主廚，根據營養師法之規定，應受下列那一種處置？ 王先生應被處十萬元以下之罰鍰 王先生本人以及飯店負責人應被處一萬五千元以上，十五萬元以下罰鍰 該觀光飯店應被撤銷營利事業登記證 王先生不必受處罰', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "e959493419d7", "answer_pdf_sha1": "ec7f59b9c927", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11462', 'dietitian', 'dietitian-moex-092-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某瘦身美容中心雇用無照營養師擔任該中心營養諮詢的工作，請問依營養師法之規定，應受下列何種處罰？ 該中心應勒令停業 營養師處三十萬元以下罰鍰 營養師及該中心負責人應各處新台幣十五萬元以上罰鍰 營養師及該中心負責人應各處新台幣一萬五千元以上，十五萬元以下罰鍰', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "e959493419d7", "answer_pdf_sha1": "ec7f59b9c927", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11463', 'dietitian', 'dietitian-moex-092-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '周小姐通過專技高考營養師考試後，應持考試合格證書向下列何單位申請營養師證書？ 考試院  行政院衛生署  各地衛生局  各地衛生所', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "e959493419d7", "answer_pdf_sha1": "ec7f59b9c927", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
